xpath.script:
document.addEventListener('DOMContentLoaded', function () {
    var shopCheckout = document.getElementById('shop_checkout');
    var pickupToggle = document.getElementById('andyka_pickup_toggle');
    var optDelivery = document.getElementById('andyka_opt_delivery');
    var optPickup = document.getElementById('andyka_opt_pickup');
    var deliveryForm = document.getElementById('o_delivery_form');
    var deliveryAddressRow = document.getElementById('delivery_address_row');
    var deliveryDetail = document.getElementById('andyka_delivery_detail');
    var pickupDetail = document.getElementById('andyka_pickup_detail');

    if (!shopCheckout || !pickupToggle) return;

    shopCheckout.insertBefore(pickupToggle, shopCheckout.firstChild);

    if (deliveryForm) deliveryForm.style.display = 'none';
    var billingRow = document.getElementById('billing_address_row');
    if (billingRow) billingRow.style.display = 'none';
    if (!billingRow) {
        var t = document.getElementById('use_delivery_as_billing');
        if (t) { var s = t.closest('.mb-3, .mb-4'); if (s) s.style.display = 'none'; }
    }

    function findCarrierRadio(keyword) {
        var radios = document.querySelectorAll('#o_delivery_methods input[type="radio"]');
        var found = null;
        radios.forEach(function(r) {
            var li = r.closest('li');
            var label = li ? li.querySelector('.o_delivery_carrier_label') : null;
            var name = label ? label.textContent.trim().toLowerCase() : '';
            if (name.indexOf(keyword) !== -1) found = r;
        });
        return found;
    }

    function rpcCall(url, params) {
        return fetch(url, {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({ jsonrpc: '2.0', method: 'call', id: 1, params: params })
        }).then(function(res) { return res.json(); });
    }

    function setCarrierAndGetRate(dmId) {
        rpcCall('/shop/set_delivery_method', { dm_id: parseInt(dmId) })
        .then(function(data) {
            if (data.result) {
                updateCartSummary(data.result);
                return rpcCall('/shop/get_delivery_rate', { dm_id: parseInt(dmId) });
            }
        })
        .then(function(rateData) {
            if (rateData && rateData.result) showDeliveryDetail(rateData.result);
        })
        .catch(function(err) { console.error('[Checkout] Error:', err); });
    }

    function setCarrierOnly(dmId) {
        rpcCall('/shop/set_delivery_method', { dm_id: parseInt(dmId) })
        .then(function(data) {
            if (data.result) updateCartSummary(data.result);
        })
        .catch(function(err) { console.error('[Checkout] Error:', err); });
    }

    function updateCartSummary(result) {
        var el;
        el = document.querySelector('#order_delivery .monetary_field');
        if (el && result.amount_delivery != null) el.innerHTML = result.amount_delivery;
        el = document.querySelector('#order_total .monetary_field');
        if (el && result.amount_total != null) el.innerHTML = result.amount_total;
        el = document.querySelector('#order_total_untaxed .monetary_field');
        if (el && result.amount_untaxed != null) el.innerHTML = result.amount_untaxed;
    }

    function showDeliveryDetail(rate) {
        if (!deliveryDetail) return;
        var distEl = document.getElementById('andyka_distance_text');
        var costEl = document.getElementById('andyka_delivery_cost_text');

        if (rate.warning_message && distEl) {
            distEl.textContent = rate.warning_message;
        } else if (distEl) {
            distEl.textContent = '';
        }

        if (rate.success && rate.amount_delivery && costEl) {
            costEl.innerHTML = rate.amount_delivery;
        } else if (rate.error_message && costEl) {
            costEl.innerHTML = '' + rate.error_message + '';
        }

        deliveryDetail.style.display = 'block';
    }

    function switchToPickup() {
        if (pickupDetail) pickupDetail.style.display = 'block';
        if (deliveryDetail) deliveryDetail.style.display = 'none';
        if (deliveryAddressRow) deliveryAddressRow.style.display = 'none';
        var spRadio = findCarrierRadio('ambil sendiri') || findCarrierRadio('self pickup');
        if (spRadio) {
            var dmId = spRadio.dataset.dmId || spRadio.value;
            if (dmId) setCarrierOnly(dmId);
        }
    }

    function switchToDelivery() {
        if (pickupDetail) pickupDetail.style.display = 'none';
        if (deliveryAddressRow) deliveryAddressRow.style.display = '';
        var dlRadio = findCarrierRadio('berdasarkan jarak') || findCarrierRadio('gopokaja');
        if (dlRadio) {
            var dmId = dlRadio.dataset.dmId || dlRadio.value;
            if (dmId) setCarrierAndGetRate(dmId);
        }
    }

    if (optDelivery) optDelivery.addEventListener('change', function () { if (this.checked) switchToDelivery(); });
    if (optPickup) optPickup.addEventListener('change', function () { if (this.checked) switchToPickup(); });

    if (deliveryAddressRow) {
        deliveryAddressRow.addEventListener('click', function(e) {
            var card = e.target.closest('.o_wsale_address_card, .card');
            if (card && optDelivery && optDelivery.checked) {
                setTimeout(function() {
                    var dlRadio = findCarrierRadio('berdasarkan jarak') || findCarrierRadio('gopokaja');
                    if (dlRadio) {
                        var dmId = dlRadio.dataset.dmId || dlRadio.value;
                        if (dmId) setCarrierAndGetRate(dmId);
                    }
                }, 1500);
            }
        });
    }

    setTimeout(function() {
        if (optDelivery && optDelivery.checked) {
            var dlRadio = findCarrierRadio('berdasarkan jarak') || findCarrierRadio('gopokaja');
            if (dlRadio) {
                var dmId = dlRadio.dataset.dmId || dlRadio.value;
                if (dmId) setCarrierAndGetRate(dmId);
            }
        }
    }, 800);
});
